// User entity with MFA enabled flag and backup codes list
@Entity
public class User {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    
    private String username;
    
    private boolean mfaEnabled;
    
    @OneToMany(mappedBy = "user", cascade = CascadeType.ALL, orphanRemoval = true)
    private List<BackupCode> backupCodes;

    // Getters and setters
}

// Backup code entity with unique code and user association
@Entity
public class BackupCode {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    
    private String code;
    
    @ManyToOne
    @JoinColumn(name = "user_id")
    private User user;

    // Getters and setters
}

// Service for generating backup codes
@Service
public class BackupCodeService {
    @Autowired
    private UserRepository userRepository;
    
    public List<String> generateBackupCodes(User user) {
        if (user.getMfaEnabled()) {
            List<String> codes = new ArrayList<>();
            for (int i = 0; i < 10; i++) {
                String code = UUID.randomUUID().toString();
                BackupCode backupCode = new BackupCode(code, user);
                userRepository.save(backupCode);
                codes.add(code);
            }
            return codes;
        } else {
            return Collections.emptyList();
        }
    }
}

// Controller for handling MFA and backup code related requests
@RestController
@RequestMapping("/api/users")
public class UserController {
    @Autowired
    private BackupCodeService backupCodeService;
    
    @PostMapping("/{id}/enable-mfa")
    public ResponseEntity<?> enableMfa(@PathVariable Long id) {
        User user = userRepository.findById(id).orElseThrow();
        if (user.getMfaEnabled()) {
            return ResponseEntity.ok("MFA already enabled for this user");
        }
        List<String> backupCodes = backupCodeService.generateBackupCodes(user);
        user.setMfaEnabled(true);
        userRepository.save(user);
        return ResponseEntity.ok(backupCodes);
    }

    @PostMapping("/{id}/authenticate-with-backup-code")
    public ResponseEntity<?> authenticateWithBackupCode(@PathVariable Long id, @RequestParam String code) {
        User user = userRepository.findById(id).orElseThrow();
        BackupCode backupCode = user.getBackupCodes().stream()
                .filter(bc -> bc.getCode().equals(code))
                .findFirst()
                .orElseThrow(() -> new RuntimeException("Invalid backup code"));
        return ResponseEntity.ok("Authenticated successfully");
    }
}

